package com.lifeservice.cache;

import cn.hutool.core.lang.UUID;
import cn.hutool.core.util.BooleanUtil;
import cn.hutool.core.util.RandomUtil;
import cn.hutool.core.util.StrUtil;
import cn.hutool.json.JSONUtil;
import com.github.benmanes.caffeine.cache.Cache;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.data.redis.core.script.DefaultRedisScript;
import org.springframework.stereotype.Component;

import javax.annotation.Resource;
import java.time.LocalDateTime;
import java.util.Collections;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.function.Function;

import static com.lifeservice.cache.RedisConstants.*;

/**
 * 缓存客户端工具
 */
@Slf4j
@Component
public class CacheClient {

    @Resource
    private StringRedisTemplate stringRedisTemplate;

    @Resource
    private Cache<String, Object> caffeineCache;

    @Resource
    private ExecutorService cacheRebuildExecutor;

    private static final DefaultRedisScript<Long> UNLOCK_SCRIPT;

    static {
        UNLOCK_SCRIPT = new DefaultRedisScript<>();
        UNLOCK_SCRIPT.setResultType(Long.class);
        UNLOCK_SCRIPT.setScriptText(
                "if redis.call('get', KEYS[1]) == ARGV[1] then " +
                "return redis.call('del', KEYS[1]) " +
                "else " +
                "return 0 " +
                "end"
        );
    }

    /**
     * 设置普通缓存（带 TTL 随机打散）
     */
    public void set(String key, Object value, Long time, TimeUnit unit) {
        if (value == null) {
            throw new IllegalArgumentException("Cache value cannot be null!");
        }
        long ttlSeconds = unit.toSeconds(time) + RandomUtil.randomLong(60, 300);
        stringRedisTemplate.opsForValue().set(key, JSONUtil.toJsonStr(value), ttlSeconds, TimeUnit.SECONDS);
        caffeineCache.put(key, value);
    }

    /**
     * 设置逻辑过期缓存
     */
    public void setWithLogicalExpire(String key, Object value, Long time, TimeUnit unit) {
        if (value == null) {
            throw new IllegalArgumentException("Logical expire data cannot be null!");
        }
        RedisData redisData = new RedisData();
        redisData.setData(value);
        redisData.setExpireTime(LocalDateTime.now().plusSeconds(unit.toSeconds(time)));
        
        String json = JSONUtil.toJsonStr(redisData);
        stringRedisTemplate.opsForValue().set(key, json);
        caffeineCache.put(key, redisData);
    }

    /**
     * 二级缓存查询：解决缓存穿透
     */
    public <R, ID> R queryWithPassThrough(
            String keyPrefix, ID id, Class<R> type, Function<ID, R> dbFallback, Long time, TimeUnit unit) {
        String key = keyPrefix + id;
        
        // 1. L1
        Object cachedObj = caffeineCache.getIfPresent(key);
        if (cachedObj != null) {
            if (CACHE_NULL_VALUE.equals(cachedObj)) return null;
            return type.cast(cachedObj);
        }

        // 2. L2
        String json = stringRedisTemplate.opsForValue().get(key);
        if (StrUtil.isNotBlank(json)) {
            if (CACHE_NULL_VALUE.equals(json)) {
                caffeineCache.put(key, CACHE_NULL_VALUE);
                return null;
            }
            R r = JSONUtil.toBean(json, type);
            caffeineCache.put(key, r);
            return r;
        }
        
        if (json != null) {
            caffeineCache.put(key, CACHE_NULL_VALUE);
            return null;
        }

        // 3. DB
        R result = dbFallback.apply(id);
        if (result == null) {
            stringRedisTemplate.opsForValue().set(key, CACHE_NULL_VALUE, CACHE_NULL_TTL, TimeUnit.MINUTES);
            caffeineCache.put(key, CACHE_NULL_VALUE);
            return null;
        }

        this.set(key, result, time, unit);
        return result;
    }

    /**
     * 二级缓存查询：逻辑过期
     */
    public <R, ID> R queryWithLogicalExpire(
            String keyPrefix, ID id, Class<R> type, Function<ID, R> dbFallback, Long time, TimeUnit unit) {
        String key = keyPrefix + id;

        RedisData redisData = getRedisDataSafe(keyPrefix, id, type, dbFallback, time, unit);
        
        if (redisData == null) {
            return null; 
        }

        R result = JSONUtil.toBean(JSONUtil.toJsonStr(redisData.getData()), type);
        LocalDateTime expireTime = redisData.getExpireTime();

        if (expireTime.isAfter(LocalDateTime.now())) {
            return result; 
        }

        String lockKey = LOCK_KEY_PREFIX + key;
        String token = tryLock(lockKey);
        if (token != null) {
            try {
                cacheRebuildExecutor.submit(() -> {
                    try {
                        R r1 = dbFallback.apply(id);
                        if (r1 == null) {
                            stringRedisTemplate.opsForValue().set(key, CACHE_NULL_VALUE, CACHE_NULL_TTL, TimeUnit.MINUTES);
                            caffeineCache.put(key, CACHE_NULL_VALUE);
                        } else {
                            this.setWithLogicalExpire(key, r1, time, unit);
                        }
                    } catch (Exception e) {
                        log.error("Cache rebuild error", e);
                    } finally {
                        unlock(lockKey, token);
                    }
                });
            } catch (Exception e) {
                unlock(lockKey, token);
            }
        }

        return result; 
    }

    private <R, ID> RedisData getRedisDataSafe(
            String keyPrefix, ID id, Class<R> type, Function<ID, R> dbFallback, Long time, TimeUnit unit) {
        String key = keyPrefix + id;
        
        Object obj = caffeineCache.getIfPresent(key);
        if (obj instanceof RedisData) return (RedisData) obj;
        if (CACHE_NULL_VALUE.equals(obj)) return null;

        String json = stringRedisTemplate.opsForValue().get(key);
        if (StrUtil.isNotBlank(json)) {
            if (CACHE_NULL_VALUE.equals(json)) {
                caffeineCache.put(key, CACHE_NULL_VALUE);
                return null;
            }
            RedisData rd = JSONUtil.toBean(json, RedisData.class);
            caffeineCache.put(key, rd);
            return rd;
        }
        
        if (json != null) {
            caffeineCache.put(key, CACHE_NULL_VALUE);
            return null;
        }

        R dbResult = dbFallback.apply(id);
        if (dbResult == null) {
            stringRedisTemplate.opsForValue().set(key, CACHE_NULL_VALUE, CACHE_NULL_TTL, TimeUnit.MINUTES);
            caffeineCache.put(key, CACHE_NULL_VALUE);
            return null;
        }

        RedisData rd = new RedisData();
        rd.setData(dbResult);
        rd.setExpireTime(LocalDateTime.now().plusSeconds(unit.toSeconds(time)));
        this.setWithLogicalExpire(key, dbResult, time, unit);
        return rd;
    }

    private String tryLock(String key) {
        String token = UUID.randomUUID().toString(true);
        Boolean flag = stringRedisTemplate.opsForValue().setIfAbsent(key, token, 10, TimeUnit.SECONDS);
        return BooleanUtil.isTrue(flag) ? token : null;
    }

    private void unlock(String key, String token) {
        stringRedisTemplate.execute(UNLOCK_SCRIPT, Collections.singletonList(key), token);
    }

    /**
     * 失效缓存逻辑
     * 当前实现：同步删除 Redis(L2) 和当前实例本地 Caffeine(L1)。
     */
    public void delete(String key) {
        stringRedisTemplate.delete(key);
        caffeineCache.invalidate(key);
    }
}

package com.lifeservice.canal;

import com.alibaba.otter.canal.client.CanalConnector;
import com.alibaba.otter.canal.client.CanalConnectors;
import com.alibaba.otter.canal.protocol.CanalEntry;
import com.alibaba.otter.canal.protocol.Message;
import com.google.protobuf.InvalidProtocolBufferException;
import com.lifeservice.cache.CacheInvalidationPublisher;
import com.lifeservice.dto.CacheInvalidateMessage;
import com.lifeservice.properties.CanalProperties;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import javax.annotation.PreDestroy;
import javax.annotation.Resource;
import java.net.InetSocketAddress;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;

/**
 * Canal Binlog 监听器 (重构版：集成 MQ 广播失效)
 */
@Slf4j
@Component
public class ShopCanalListener {

    @Resource
    private CanalProperties canalProperties;

    @Resource
    private CacheInvalidationPublisher cacheInvalidationPublisher;

    @Resource(name = "canalExecutorService")
    private ExecutorService executorService;

    @Value("${app.canal.enabled:true}")
    private boolean enabled;

    private CanalConnector connector;

    private volatile boolean running = true;

    private static final String TARGET_SCHEMA = "lifeservice";
    private static final String TARGET_TABLE = "tb_shop";

    @PostConstruct
    public void start() {
        if (!enabled) {
            log.info("Canal 监听器已根据配置禁用。");
            return;
        }
        connector = CanalConnectors.newSingleConnector(
                new InetSocketAddress(canalProperties.getHost(), canalProperties.getPort()),
                canalProperties.getDestination(),
                canalProperties.getUsername(),
                canalProperties.getPassword()
        );

        executorService.submit(this::worker);
        log.info("Canal 客户端（MQ 模式）启动成功。");
    }

    private void worker() {
        while (running) {
            try {
                connector.connect();
                connector.subscribe("lifeservice\\.tb_shop");
                connector.rollback();

                while (running) {
                    Message message = connector.getWithoutAck(canalProperties.getBatchSize());
                    long batchId = message.getId();
                    int size = message.getEntries().size();

                    if (batchId == -1 || size == 0) {
                        if (!sleep(1000)) break;
                        continue;
                    }

                    try {
                        processEntries(batchId, message.getEntries());
                        connector.ack(batchId);
                    } catch (Exception e) {
                        log.error("处理 Canal 批次失败，准备回滚。batchId={}", batchId, e);
                        connector.rollback(batchId);
                    }
                }
            } catch (Exception e) {
                if (running) {
                    log.error("Canal 连接器错误，5秒后重试", e);
                    if (!sleep(5000)) break;
                }
            } finally {
                disconnectQuietly();
            }
        }
    }

    private void processEntries(long batchId, List<CanalEntry.Entry> entries) {
        for (CanalEntry.Entry entry : entries) {
            if (entry.getEntryType() != CanalEntry.EntryType.ROWDATA) {
                continue;
            }

            CanalEntry.Header header = entry.getHeader();
            String schemaName = header.getSchemaName();
            String tableName = header.getTableName();

            if (!TARGET_SCHEMA.equalsIgnoreCase(schemaName) || !TARGET_TABLE.equalsIgnoreCase(tableName)) {
                continue;
            }

            CanalEntry.RowChange rowChange;
            try {
                rowChange = CanalEntry.RowChange.parseFrom(entry.getStoreValue());
            } catch (InvalidProtocolBufferException e) {
                throw new RuntimeException("解析 RowChange 失败", e);
            }

            CanalEntry.EventType eventType = rowChange.getEventType();
            if (!isDmlEvent(eventType)) {
                continue;
            }

            List<Long> ids = new ArrayList<>();
            for (CanalEntry.RowData rowData : rowChange.getRowDatasList()) {
                List<CanalEntry.Column> columns = (eventType == CanalEntry.EventType.DELETE)
                        ? rowData.getBeforeColumnsList()
                        : rowData.getAfterColumnsList();
                
                String idStr = getColumnValue(columns, "id");
                if (idStr != null) {
                    ids.add(Long.parseLong(idStr));
                }
            }

            if (ids.isEmpty()) continue;

            CacheInvalidateMessage message = CacheInvalidateMessage.builder()
                    .cacheType("shop")
                    .table(tableName)
                    .operation(eventType.name())
                    .ids(ids)
                    .timestamp(System.currentTimeMillis())
                    .build();

            cacheInvalidationPublisher.publish(message);
        }
    }

    private boolean isDmlEvent(CanalEntry.EventType eventType) {
        return eventType == CanalEntry.EventType.INSERT
                || eventType == CanalEntry.EventType.UPDATE
                || eventType == CanalEntry.EventType.DELETE;
    }

    private String getColumnValue(List<CanalEntry.Column> columns, String name) {
        for (CanalEntry.Column column : columns) {
            if (column.getName().equalsIgnoreCase(name)) {
                return column.getValue();
            }
        }
        return null;
    }

    private boolean sleep(long ms) {
        try {
            Thread.sleep(ms);
            return true;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return false;
        }
    }

    private void disconnectQuietly() {
        if (connector != null) {
            try {
                connector.disconnect();
            } catch (Exception e) {
                // ignore
            }
        }
    }

    @PreDestroy
    public void stop() {
        running = false;
        disconnectQuietly();
    }
}

package com.lifeservice.config;

import org.springframework.amqp.core.*;
import org.springframework.amqp.support.converter.Jackson2JsonMessageConverter;
