@Configuration
public class RabbitMqConfig {

    // --- 缓存广播相关配置 (原有) ---
    @Value("${app.rabbitmq.exchange:cache.fanout.exchange}")
    private String exchangeName;

    @Value("${app.rabbitmq.queue}")
    private String queueName;

    @Bean
    public FanoutExchange cacheFanoutExchange() {
        return new FanoutExchange(exchangeName, true, false);
    }

    @Bean
    public Queue cacheQueue() {
        return new Queue(queueName, false, true, true);
    }

    @Bean
    public Binding bindingCacheQueue(Queue cacheQueue, FanoutExchange cacheFanoutExchange) {
        return BindingBuilder.bind(cacheQueue).to(cacheFanoutExchange);
    }

    // --- 秒杀订单异步处理配置 (新增) ---
    public static final String SECKILL_EXCHANGE = "seckill.order.exchange";
    public static final String SECKILL_QUEUE = "seckill.order.queue";
    public static final String SECKILL_ROUTING_KEY = "seckill.order";

    @Bean
    public DirectExchange seckillExchange() {
        return new DirectExchange(SECKILL_EXCHANGE, true, false);
    }

    @Bean
    public Queue seckillQueue() {
        // 秒杀订单队列设为持久化
        return new Queue(SECKILL_QUEUE, true, false, false);
    }

    @Bean
    public Binding bindingSeckillQueue(Queue seckillQueue, DirectExchange seckillExchange) {
        return BindingBuilder.bind(seckillQueue).to(seckillExchange).with(SECKILL_ROUTING_KEY);
    }

    @Bean
    public MessageConverter jsonMessageConverter() {
        return new Jackson2JsonMessageConverter();
    }
}

package com.lifeservice.config;

import com.lifeservice.cache.RedisConstants;
import com.lifeservice.entity.SeckillVoucher;
import com.lifeservice.service.ISeckillVoucherService;
import lombok.extern.slf4j.Slf4j;
import org.springframework.boot.CommandLineRunner;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.stereotype.Component;

import javax.annotation.Resource;
import java.time.LocalDateTime;
import java.util.List;

/**
 * 秒杀库存预热：项目启动时，将未结束的秒杀券库存同步到 Redis
 */
@Slf4j
@Component
public class SeckillStockWarmUpRunner implements CommandLineRunner {

    @Resource
    private ISeckillVoucherService seckillVoucherService;

    @Resource
    private StringRedisTemplate stringRedisTemplate;

    @Override
    public void run(String... args) throws Exception {
        
        // 1. 查询数据库中未结束的秒杀券 (endTime >= now)
        List<SeckillVoucher> seckillVouchers = seckillVoucherService.lambdaQuery()
                .ge(SeckillVoucher::getEndTime, LocalDateTime.now())
                .list();

        if (seckillVouchers == null || seckillVouchers.isEmpty()) {
            return;
        }

        // 2. 将库存重建到 Redis
        int count = 0;
        for (SeckillVoucher voucher : seckillVouchers) {
            // key = SECKILL_STOCK_KEY + voucherId
            String key = RedisConstants.SECKILL_STOCK_KEY + voucher.getVoucherId();
            // 写入时转成字符串，StringRedisTemplate 只能操作 String
            stringRedisTemplate.opsForValue().set(key, voucher.getStock().toString());
            count++;
        }

    }
}

package com.lifeservice.config;

import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * 线程池配置
 */
@Slf4j
@Configuration
public class ThreadPoolConfig {

    /**
     * 缓存重建线程池
     */
    @Bean
    public ExecutorService cacheRebuildExecutor() {
        return new ThreadPoolExecutor(
                4,
                8,
                60L,
                TimeUnit.SECONDS,
                new LinkedBlockingQueue<>(100),
                new ThreadFactory() {
                    private final AtomicInteger threadNum = new AtomicInteger(1);
                    @Override
                    public Thread newThread(Runnable r) {
                        Thread t = new Thread(r);
                        t.setName("cache-rebuild-" + threadNum.getAndIncrement());
                        return t;
                    }
                },
                (r, executor) -> {
                    log.error("Cache rebuild thread pool is full! Task rejected.");
                    throw new RejectedExecutionException("Cache rebuild task rejected");
                }
        );
    }

    /**
     * Canal 消费专用线程池 (Spring 托管)
     * 
     * 配置说明：
     * - 单线程顺序消费：coreSize=1, maxSize=1
     * - 队列：100 容量的 LinkedBlockingQueue
     * - 线程特性：daemon = true，名称格式为 canal-shop-worker-x
     */
    @Bean
    public ExecutorService canalExecutorService() {
        return new ThreadPoolExecutor(
                1,
                1,
                60L,
                TimeUnit.SECONDS,
                new LinkedBlockingQueue<>(100),
                new ThreadFactory() {
                    private final AtomicInteger threadNum = new AtomicInteger(1);
                    @Override
                    public Thread newThread(Runnable r) {
                        Thread t = new Thread(r);
                        t.setName("canal-shop-worker-" + threadNum.getAndIncrement());
                        t.setDaemon(true);
                        return t;
                    }
                },
                (r, executor) -> {
                    log.error("Canal shop worker thread pool is full! Task rejected.");
                    throw new RejectedExecutionException("Canal shop worker task rejected");
                }
        );
    }
}

